import {
    type Device,
    type TestConversationInfo,
    INTERNAL_CATEGORIES,
    type Memory,
    type MockMemory,
    type NamedValue,
    AGENT_MEMORY_CONVERSATION_SUMMARY,
    AGENT_MEMORY_USER_PREFERENCES,
} from "./api";
import type {
    CallContinuedEvent,
    InitiatePayResultEvent,
    PaymentCaptureStatusEvent,
    SensitiveFieldResultEvent,
} from "@sierra/agent";

export class ReplayTestBuilder {
    private static instance?: ReplayTestBuilder;

    private allTests: ReplayTest[] = [];
    private testConfigMap: { [key: string]: string } = {};
    private memoryStack: Memory[];
    private device?: Device;
    private conversationInfo?: TestConversationInfo;
    private messageStack: ReplayTestMessage[];
    private testIds: Set<string>;
    private categoryStack: string[][];
    private descriptionStack: string[];
    private agentIdsByTestId: { [key: string]: string[] };
    private agentIdsStack: string[][];
    private simulation: boolean = false;
    private simulationOptionsStack: ReplaySimulationOptions[];
    private systemsSimulationOptionsStack: ReplaySystemsSimulationOptions[];
    private issueIdsStack: string[][];
    private simulationStartIndex: number | undefined;
    private critical: boolean = false;
    private mockMemoryStack: MockMemory[];
    private eventFixturesStack: EventFixture[][] = [];

    private constructor() {
        this.messageStack = [];
        this.memoryStack = [];
        this.testIds = new Set();
        this.categoryStack = [];
        this.agentIdsStack = [];
        this.descriptionStack = [];
        this.agentIdsByTestId = {};
        this.simulationOptionsStack = [];
        this.systemsSimulationOptionsStack = [];
        this.issueIdsStack = [];
        this.mockMemoryStack = [];
    }

    // Gets the singleton instance of ReplayTestBuilder that is responsible
    // for maintaining current accumulated state for tests being built
    // as well as a list of tests that have been saved
    static get() {
        if (!ReplayTestBuilder.instance) {
            ReplayTestBuilder.instance = new ReplayTestBuilder();
        }
        return ReplayTestBuilder.instance;
    }

    // Gets the in-progress list of messages based on our current
    // location in the tree
    getMessages() {
        return [...this.messageStack];
    }

    getMessageCount() {
        return this.messageStack.length;
    }

    addMemory(memory: Memory) {
        this.memoryStack.push(memory);
    }

    getMemory(): Memory {
        if (this.memoryStack.length === 0) {
            return {} as Memory;
        }

        return {
            variables: Object.values(
                this.memoryStack.reduce<{ [key: string]: NamedValue }>((acc, memory) => {
                    if (!memory.variables) {
                        return acc;
                    }

                    for (const v of memory.variables) {
                        if (typeof acc[v.name] !== "undefined" && acc[v.name].value !== v.value) {
                            throw new Error(`Memory variable "${v.name}" has conflicting values`);
                        }
                        acc[v.name] = v;
                    }
                    return acc;
                }, {})
            ),
            secrets: Object.values(
                this.memoryStack.reduce<{ [key: string]: NamedValue }>((acc, memory) => {
                    if (!memory.secrets) {
                        return acc;
                    }

                    for (const s of memory.secrets) {
                        if (typeof acc[s.name] !== "undefined" && acc[s.name].value !== s.value) {
                            throw new Error(`Memory secret "${s.name}" has conflicting values`);
                        }
                        acc[s.name] = s;
                    }
                    return acc;
                }, {})
            ),
        };
    }

    popMemory() {
        this.memoryStack.pop();
    }

    setDevice(device: Device | undefined) {
        this.device = device;
    }

    getDevice(): Device | undefined {
        return this.device;
    }

    setConversationInfo(conversationInfo: TestConversationInfo | undefined) {
        this.conversationInfo = conversationInfo;
    }

    getConversationInfo(): TestConversationInfo | undefined {
        return this.conversationInfo;
    }

    addCategories(categories: string[]) {
        this.categoryStack.push(categories);
    }

    getCategories(): string[] {
        return this.mergeStack(this.categoryStack, []);
    }

    popCategories() {
        this.categoryStack.pop();
    }

    addAgentIds(agentIds: string[]) {
        this.agentIdsStack.push(agentIds);
    }

    popAgentIds() {
        this.agentIdsStack.pop();
    }

    addDescription(description: string) {
        this.descriptionStack.push(description);
    }

    popDescription() {
        this.descriptionStack.pop();
    }

    getDescription(): string {
        if (this.descriptionStack.length === 0) {
            return "";
        }
        return this.descriptionStack.join(" / ");
    }

    addMessages(messages: ReplayTestMessage[]) {
        this.messageStack.push(...messages);
    }

    setSimulation(simulation: boolean) {
        this.simulation = simulation;
    }

    isSimulation(): boolean {
        return this.simulation;
    }

    setSimulationStartIndex(simulationStartIndex: number | undefined) {
        this.simulationStartIndex = simulationStartIndex;
    }

    getSimulationStartIndex(): number | undefined {
        return this.simulationStartIndex;
    }

    addSimulationOptions(options: ReplaySimulationOptions) {
        this.simulationOptionsStack.push(options);
    }

    getSimulationOptions(): ReplaySimulationOptions {
        return this.simulationOptionsStack.reduce<ReplaySimulationOptions>((acc, options) => {
            return { ...acc, ...options };
        }, {});
    }

    popSimulationOptions() {
        this.simulationOptionsStack.pop();
    }

    addSystemsSimulationOptions(options: ReplaySystemsSimulationOptions) {
        this.systemsSimulationOptionsStack.push(options);
    }

    getSystemsSimulationOptions(): ReplaySystemsSimulationOptions {
        return this.systemsSimulationOptionsStack.reduce<ReplaySystemsSimulationOptions>(
            (acc, options) => {
                return { ...acc, ...options };
            },
            {}
        );
    }

    popSystemsSimulationOptions() {
        this.systemsSimulationOptionsStack.pop();
    }

    setCritical(isCritical: boolean) {
        this.critical = isCritical;
    }

    isCritical(): boolean {
        return this.critical;
    }

    addIssueIds(issueIds: string[]) {
        this.issueIdsStack.push(issueIds);
    }

    popIssueIds() {
        this.issueIdsStack.pop();
    }

    addMockMemory(mockMemory: MockMemory) {
        this.mockMemoryStack.push(mockMemory);
    }

    popMockMemory() {
        this.mockMemoryStack.pop();
    }

    // Converts the friendly MockMemory type to the proto-compatible agentMemoryMockData format.
    // Returns undefined if no mock memory is set.
    private getMockMemoryData(): AgentMemoryMockData | undefined {
        if (this.mockMemoryStack.length === 0) {
            return undefined;
        }
        const current = this.mockMemoryStack[this.mockMemoryStack.length - 1];
        const entries: AgentMemoryMockDataEntry[] = [];
        for (const s of current.conversationSummaries ?? []) {
            entries.push({
                facts: s.facts,
                metadata: { conversationTimestamp: s.conversationTimestamp },
                recipeId: AGENT_MEMORY_CONVERSATION_SUMMARY,
            });
        }
        for (const p of current.userPreferences ?? []) {
            entries.push({
                facts: p.facts,
                metadata: { conversationTimestamp: p.conversationTimestamp },
                recipeId: AGENT_MEMORY_USER_PREFERENCES,
            });
        }
        return entries.length > 0 ? { entries } : undefined;
    }

    addEventFixtures(fixtures: EventFixture[]) {
        this.eventFixturesStack.push(fixtures);
    }

    getEventFixtures(): EventFixture[] {
        return this.eventFixturesStack.flat();
    }

    getSerializedEventFixtures(): ReplayEventFixture[] {
        return this.getEventFixtures().map(f => ({
            triggerEventType: f.triggerEventType,
            clientEventsJson: f.clientEvents.map(e => JSON.stringify(e)),
        })) as ReplayEventFixture[];
    }

    popEventFixtures() {
        this.eventFixturesStack.pop();
    }

    // Adds this set of tag assertions to the most recent message.
    // When executing the test, these assertions will be evaluated after the
    // agent response to this user message.
    addTagAssertions(assertions: string[]) {
        if (this.messageStack.length === 0) {
            throw new Error("Cannot add assertions to empty message stack");
        }

        let required = assertions.filter(t => !t.startsWith("!"));
        let prohibited = assertions.filter(t => t.startsWith("!")).map(t => t.substring(1));

        const lastMessage = this.messageStack[this.messageStack.length - 1];
        if (lastMessage.assertions) {
            required = [...(lastMessage.assertions.requiredTags ?? []), ...required];
            prohibited = [...(lastMessage.assertions.prohibitedTags ?? []), ...prohibited];
        }
        const requiredSet = new Set(required);
        for (const p of prohibited) {
            if (requiredSet.has(p)) {
                throw new Error(`Tag: ${p} has both negative and positive assertions`);
            }
        }
        lastMessage.assertions = {
            requiredTags: [...requiredSet],
            prohibitedTags: [...new Set(prohibited)],
        };
    }

    addExpectedOutcomes(expectations: string[]) {
        if (this.messageStack.length === 0) {
            throw new Error("Cannot add expected outcomes to empty message stack");
        }
        const lastMessage = this.messageStack[this.messageStack.length - 1];
        const newExpectations = [
            ...(lastMessage.assertions?.expectedOutcomes ?? []),
            ...expectations,
        ];
        if (lastMessage.assertions) {
            lastMessage.assertions.expectedOutcomes = newExpectations;
        } else {
            lastMessage.assertions = {
                requiredTags: [],
                prohibitedTags: [],
                expectedOutcomes: newExpectations,
            };
        }
    }

    addExpectedExtractions(expectations: string[]) {
        if (this.messageStack.length === 0) {
            throw new Error("Cannot add expected extractions to empty message stack");
        }
        const lastMessage = this.messageStack[this.messageStack.length - 1];
        const newExpectations = [
            ...(lastMessage.assertions?.expectedExtractions ?? []),
            ...expectations,
        ];
        if (lastMessage.assertions) {
            lastMessage.assertions.expectedExtractions = newExpectations;
        } else {
            lastMessage.assertions = {
                requiredTags: [],
                prohibitedTags: [],
                expectedExtractions: newExpectations,
            };
        }
    }

    getLastMessageAssertions(): ReplayTestAssertions | undefined {
        if (this.messageStack.length === 0) {
            throw new Error("Cannot get assertions from empty message stack");
        }
        return this.messageStack[this.messageStack.length - 1].assertions;
    }

    resetLastMessageAssertions(assertions?: ReplayTestAssertions) {
        if (this.messageStack.length === 0) {
            throw new Error("Cannot reset assertions on empty message stack");
        }
        this.messageStack[this.messageStack.length - 1].assertions = assertions;
    }

    // Pops the given number of messages off our message stack
    popMessages(numMessages: number) {
        this.messageStack = this.messageStack.slice(0, -numMessages);
    }

    // Creates a test object with the given id and the memory and set of messages
    // that have been accumulated
    saveTest(id: string, categories: string[], agentIds: string[], name?: string) {
        if (this.testIds.has(id)) {
            throw new Error(`Already have a test with ID: "${id}"; test IDs must be unique`);
        }
        this.testIds.add(id);
        const allCategories = this.mergeStack(this.categoryStack, categories);
        const allAgentIds = this.mergeStack(this.agentIdsStack, agentIds);
        const allIssueIds = this.mergeStack(this.issueIdsStack, []);
        // Manually serialize so that the ordering of messages and memory fields is deterministic
        const eventFixtures = this.getEventFixtures();
        const testConfig = JSON.stringify({
            isSimulation: this.isSimulation(),
            messages: this.getMessages(),
            memory: this.getMemory(),
            device: this.getDevice(),
            conversationInfo: this.getConversationInfo(),
            simulationOptions: this.getSimulationOptions(),
            ...(this.systemsSimulationOptionsStack.length > 0
                ? { systemsSimulationOptions: this.getSystemsSimulationOptions() }
                : {}),
            simulationStartIndex: this.getSimulationStartIndex(),
            ...(this.mockMemoryStack.length > 0
                ? { agentMemoryMockData: this.getMockMemoryData() }
                : {}),
            ...(eventFixtures.length > 0
                ? { eventFixtures: this.getSerializedEventFixtures() }
                : {}),
        });
        const existingTestId = this.testConfigMap[testConfig];
        if (existingTestId) {
            throw new Error(
                `Cannot create multiple tests with identical message history and configuration: "${existingTestId}" and "${id}"`
            );
        }
        this.testConfigMap[testConfig] = id;
        this.allTests.push({
            id,
            name,
            isSimulation: this.isSimulation(),
            simulationOptions: this.getSimulationOptions(),
            ...(this.systemsSimulationOptionsStack.length > 0
                ? { systemsSimulationOptions: this.getSystemsSimulationOptions() }
                : {}),
            simulationStartIndex: this.getSimulationStartIndex(),
            isCritical: this.isCritical(),
            messages: this.getMessages().map(m => {
                return { ...m };
            }),
            initialMemory: this.getMemory(),
            device: this.getDevice(),
            conversationInfo: this.getConversationInfo(),
            categories: [...new Set(allCategories)].sort((a, b) => {
                // Sort internal categories to the front
                const indexA = INTERNAL_CATEGORIES.indexOf(a);
                const indexB = INTERNAL_CATEGORIES.indexOf(b);
                if (indexA !== -1 && indexB !== -1) {
                    return indexA - indexB;
                } else if (indexA !== -1) {
                    return -1;
                } else if (indexB !== -1) {
                    return 1;
                }
                return 0;
            }),
            groupDescription: this.getDescription(),
            issueIds: allIssueIds,
            agentMemoryMockData: this.getMockMemoryData(),
            ...(eventFixtures.length > 0
                ? { eventFixtures: this.getSerializedEventFixtures() }
                : {}),
        });
        this.agentIdsByTestId[id] = allAgentIds;
    }

    mergeStack(stack: string[][], newEntries: string[]): string[] {
        const merged = [];
        for (const group of stack) {
            merged.push(...group);
        }
        merged.push(...newEntries);
        return merged;
    }

    // Returns a list of all test objects that have been created.
    getAllTests(): ReplayTestSuite {
        return { tests: [...this.allTests] };
    }

    getAllTestsForAgent(agentId: string): ReplayTestSuite {
        const normalizedAgentId = agentId.split("-", 2)[1];
        return {
            tests: this.allTests.filter(t => {
                const agentIds = this.agentIdsByTestId[t.id];
                return agentIds.length === 0 || agentIds.includes(normalizedAgentId);
            }),
        };
    }
}

// These types need to be kept in sync with ReplayTestSuite and associated types
// in server/models/appdb/replay.proto since we marshal directly from this
// JSON to those protobufs
type ReplayTestSuite = {
    tests: ReplayTest[];
};

type ReplayTestAttachment = {
    type: "custom" | "file";
    data: string;
};

export type InterruptMetadata = {
    interruptFinalResponse: boolean;
    responseIndex?: number;
    deliveredPercentage: number;
};

export type ReplayTestMessage = {
    content?: string;
    attachments?: ReplayTestAttachment[];
    attachmentMessage?: string;
    assertions?: ReplayTestAssertions;
    interrupt?: boolean;
    interruptMetadata?: InterruptMetadata;
};

export type ReplayTestAssertions = {
    requiredTags?: string[];
    prohibitedTags?: string[];
    // natural language assertions on the test conversation
    expectedOutcomes?: string[];
    // natural language assertions on the memory extraction output
    expectedExtractions?: string[];
};

export type ReplaySimulationOptions = {
    // Maximum number of combined user and agent messages to simulate before
    // terminating the simulation
    maxMessages?: number;

    // LLM temperature to use when generating user responses
    temperature?: number;

    // If true, the user response generator won't include a refinement task
    // aimed at simplifying the response and ensuring that the simulated user
    // only divulges information when prompted by the agent
    skipTersenessFilter?: boolean;

    // An optional IETF language tag, e.g. "en-US", "fr-CA", etc., which is made
    // up of a language code ("en", "fr", etc.) and a optional region code
    // ("US", "CA", "GB", etc.)
    languageCode?: string;

    // If true, run configured monitors after the simulation. Defaults to false.
    runMonitors?: boolean;

    // If true, run this voice-device simulation through the real voice loop.
    simulateSpeech?: boolean;
};

// Fixture for continuation, payments, and sensitive-field events only
type FixtureClientEvent =
    | PaymentCaptureStatusEvent
    | SensitiveFieldResultEvent
    | InitiatePayResultEvent
    | CallContinuedEvent;

export type EventFixture = {
    triggerEventType: string;
    /**
     * SDK ClientEvent objects.
     * The builder sends these in TypeScript SDK format to the backend,
     * which converts them to Go wire format during replay.
     *
     * @example
     * ```typescript
     * clientEvents: [{
     *     type: "payment-capture-status",
     *     captureType: "chat-iframe",
     *     captureStatus: "success",
     *     status: { connector: "stripe", stripe: { setupIntent: { ... } } }
     * }]
     * ```
     */
    clientEvents: FixtureClientEvent[];
};

export type ReplaySystemsSimulationOptions = {
    // Whether tool calls should be simulated by an LLM instead of executing real code.
    simulateTools?: boolean;

    // Whether integration API calls should be simulated by an LLM instead of executing real code.
    simulateIntegrations?: boolean;

    // Free-text context passed to the LLM when generating simulated tool/API
    // responses. Describes customer characteristics, account flags, etc.
    // to produce realistic mock data.
    accountState?: string;
};

// Proto-compatible types for AgentMemoryMockData.
// These map directly to appdb.AgentMemoryMockData in replay.proto via JSON marshaling.
type AgentMemoryMockDataEntry = {
    facts: string[];
    metadata: { conversationTimestamp: string };
    recipeId: string;
};

type AgentMemoryMockData = {
    entries: AgentMemoryMockDataEntry[];
};

type ReplayEventFixture = {
    triggerEventType: string;
    clientEventsJson: string[];
};

type ReplayTest = {
    // TODO(rravi): rename id -> test_id after server ExtractTestSuiteFromJS code is past the rollback window
    id: string;
    name?: string;
    initialMemory?: Memory;
    device?: Device;
    conversationInfo?: TestConversationInfo;
    messages: ReplayTestMessage[];
    categories?: string[];
    groupDescription?: string;
    isSimulation?: boolean;
    simulationStartIndex?: number;
    simulationOptions?: ReplaySimulationOptions;
    systemsSimulationOptions?: ReplaySystemsSimulationOptions;
    isCritical?: boolean;
    issueIds?: string[];
    agentMemoryMockData?: AgentMemoryMockData;
    eventFixtures?: ReplayEventFixture[];
};
