export type NamedValue = {
    name: string;
    value: string;
};

export type Memory = {
    variables?: NamedValue[];
    secrets?: NamedValue[];
};

/**
 * Declares the memory variables and secrets for this set of replay
 * conversations. Only permitted before any user messages have been said.
 */
export function withMemory(memory: Memory, next: Next) {
    const testBuilder = ReplayTestBuilder.get();
    if (testBuilder.getMessageCount() > 0) {
        throw new Error("Cannot call withMemory() after say()");
    }
    testBuilder.addMemory(memory);
    handleNext(next);
    testBuilder.popMemory();
}

// Re-export for backwards compatibility
export { type UserDevice as Device } from "@sierra/agent";

// Keep in sync with journeys/sdk/core/agent-memory.ts
// Duplicated here because importing from @sierra/agent requires runtime initialization
export const AGENT_MEMORY_CONVERSATION_SUMMARY = "_conversation_summary";
export const AGENT_MEMORY_USER_PREFERENCES = "_user_preferences";

/**
 * A single mock memory entry with facts and a timestamp.
 */
export type MockMemoryEntry = {
    facts: string[];
    conversationTimestamp: string;
};

/**
 * Mock agent memory data for simulations. Allows injecting prior conversation
 * summaries and user preferences so the agent can recall them during testing.
 *
 * Example:
 * ```ts
 * withMockMemory({
 *     conversationSummaries: [{
 *         facts: ["Customer called about billing issue", "Agent offered $20 credit"],
 *         conversationTimestamp: "2026-03-15T10:00:00Z",
 *     }],
 * }, () => { ... });
 * ```
 */
export type MockMemory = {
    conversationSummaries?: MockMemoryEntry[];
    userPreferences?: MockMemoryEntry[];
};

/**
 * Declares mock agent memory data for this set of replay conversations.
 * When set, the agent's getMemory() call returns this mock data instead of
 * querying CDP. Only permitted before any user messages have been said.
 */
export function withMockMemory(mockMemory: MockMemory, next: Next) {
    const testBuilder = ReplayTestBuilder.get();
    if (testBuilder.getMessageCount() > 0) {
        throw new Error("Cannot call withMockMemory() after say()");
    }
    testBuilder.addMockMemory(mockMemory);
    handleNext(next);
    testBuilder.popMockMemory();
}

/**
 * Declares the device that will be used for this set of replay conversations.
 * Only permitted before any user messages have been said.
 */
export function withDevice(device: Device, next: Next) {
    // TODO: implement this on top of withConversationInfo() once runtime
    // support for it is deployed.
    const testBuilder = ReplayTestBuilder.get();
    if (testBuilder.getMessageCount() > 0) {
        throw new Error("Cannot call withDevice() after say()");
    }
    const oldDevice = testBuilder.getDevice();
    testBuilder.setDevice(device);
    handleNext(next);
    testBuilder.setDevice(oldDevice);
}

export type TestConversationInfo = Partial<
    Pick<
        ConversationInfo,
        // Subset of fields that can be set via agent.ConversationOptions
        | "externalConversationId"
        | "device"
        | "locale"
        | "timeZone"
        | "clientIP"
        | "clientPhoneNumber"
        | "agentPhoneNumber"
        | "outboundInfo"
        | "isVoiceOutbound"
        | "callSID"
    >
> & {
    /** @deprecated Setting a conversation ID in tests has no effect. This field will be removed in a future version. */
    id?: string;
};

/**
 * Declares the conversation info that will be used for this set of replay conversations.
 * Only permitted before any user messages have been said.
 */
export function withConversationInfo(conversationInfo: TestConversationInfo, next: Next) {
    const testBuilder = ReplayTestBuilder.get();
    if (testBuilder.getMessageCount() > 0) {
        throw new Error("Cannot call withConversationInfo() after say()");
    }
    const oldConversationInfo = testBuilder.getConversationInfo();
    testBuilder.setConversationInfo(conversationInfo);
    handleNext(next);
    testBuilder.setConversationInfo(oldConversationInfo);
}

/**
 * Enables systems simulation for all tests in this block.
 * Defaults: simulateIntegrations = true, simulateTools = false.
 * Individual tests can override via their own systemsSimulationOptions.
 */
export function withSystemsSimulation(options: ReplaySystemsSimulationOptions, next: Next) {
    const testBuilder = ReplayTestBuilder.get();
    testBuilder.addSystemsSimulationOptions({
        simulateIntegrations: options.simulateIntegrations ?? true,
        simulateTools: options.simulateTools ?? false,
        accountState: options.accountState,
    });
    handleNext(next);
    testBuilder.popSystemsSimulationOptions();
}

export { type EventFixture } from "./builder";

/**
 * Declares event fixtures for this set of replay conversations.
 * When the agent sends a trigger event (e.g., "initiate-pay"), the runner
 * injects the corresponding fixture client events in order.
 *
 * @example
 * ```typescript
 * withEventFixtures([{
 *     triggerEventType: "initiate-pay",
 *     clientEvents: [{
 *         type: "payment-capture-status",
 *         captureType: "chat-iframe",
 *         captureStatus: "success",
 *         status: {
 *             connector: "stripe",
 *             stripe: { setupIntent: { paymentMethodId: "pm_123", status: "succeeded" } }
 *         }
 *     }]
 * }], () => test("payment-test", { ... }));
 * ```
 */
export function withEventFixtures(fixtures: EventFixture[], next: Next) {
    const testBuilder = ReplayTestBuilder.get();
    testBuilder.addEventFixtures(fixtures);
    handleNext(next);
    testBuilder.popEventFixtures();
}

export function withCategories(categoryOrCategories: string | string[], next: Next) {
    const testBuilder = ReplayTestBuilder.get();
    const categories = ensureList(categoryOrCategories);
    testBuilder.addCategories(categories);
    handleNext(next);
    testBuilder.popCategories();
}

export function forAgent(agentIdOrAgentIds: string | string[], next: Next) {
    const testBuilder = ReplayTestBuilder.get();
    const agentIds = ensureList(agentIdOrAgentIds);
    testBuilder.addAgentIds(agentIds);
    handleNext(next);
    testBuilder.popAgentIds();
}

// Declares the next user message(s) that will be sent
export function say(messageInput: TestMessageInput, next: () => void) {
    const testBuilder = ReplayTestBuilder.get();
    if (testBuilder.isSimulation()) {
        throw new Error(`Cannot use say() inside simulate() ${JSON.stringify(messageInput)}`);
    }
    const messages = parseMessageInput(messageInput);
    testBuilder.addMessages(messages);
    next();
    testBuilder.popMessages(messages.length);
}

function interruptHelper(
    contents: string | TestMessage,
    interruptMetadata: InterruptMetadata,
    next: () => void
) {
    const testBuilder = ReplayTestBuilder.get();
    if (interruptMetadata.deliveredPercentage <= 0 || interruptMetadata.deliveredPercentage >= 1) {
        throw new Error(
            `Invalid deliveredPercentage value: ${interruptMetadata.deliveredPercentage}`
        );
    }
    if (
        testBuilder.getDevice() !== "voice_phone" &&
        testBuilder.getDevice() !== "voice_web" &&
        testBuilder.getDevice() !== "voice_android_sdk" &&
        testBuilder.getDevice() !== "voice_ios_sdk"
    ) {
        throw new Error("Cannot use interruptions in non-voice test conversations");
    }
    if (testBuilder.isSimulation()) {
        throw new Error("Cannot use interruptions inside simulate()");
    }
    const messages = parseMessageInput([contents]);
    messages[0] = {
        ...messages[0],
        interrupt: true,
        interruptMetadata,
    };
    testBuilder.addMessages(messages);
    next();
    testBuilder.popMessages(messages.length);
}

/**
 * Declares the next user message that will be sent, which will also
 * interrupt the previous agent response. This will interrupt the final message within
 * the previous agent response message(s).
 *
 * @param contents - The contents of the interrupting user message
 * @param deliveredPercentage - The percentage (between 0 and 1) of the agent response message
 * that will be delivered before the interruption. For instance, a value of 0.8 will allow
 * 80% of the agent response message to be delivered.
 * @param next - Contains the remainder of this replay test's logic
 */
export function interrupt(
    contents: string | TestMessage,
    deliveredPercentage: number,
    next: () => void
) {
    interruptHelper(contents, { interruptFinalResponse: true, deliveredPercentage }, next);
}

/**
 * Declares the next user message that will be sent, which will also
 * interrupt the previous agent response.
 *
 * @param contents - The contents of the interrupting user message
 * @param responseIndex - Determines which agent response message will be interrupted, since
 * the agent response may consist of a series of messages. For instance, specifying 0 will
 * most likely interrupt the progress indicator, while specifying 1 will typically interrupt
 * the first agent message after the progress indicator. To interrupt the final agent response
 * message (the most common case), use interrupt().
 * @param deliveredPercentage - The percentage (between 0 and 1) of the agent response message
 * that will be delivered before the interruption. For instance, a value of 0.8 will allow
 * 80% of the agent response message to be delivered.
 * @param next - Contains the remainder of this replay test's logic
 */
export function interruptResponseIndex(
    contents: string | TestMessage,
    responseIndex: number,
    deliveredPercentage: number,
    next: () => void
) {
    interruptHelper(
        contents,
        { interruptFinalResponse: false, responseIndex, deliveredPercentage },
        next
    );
}

type MessageExpectations =
    // inline tag expectations are there to backwards compatible to a state
    // before testing api had support for natural language assertions
    | string // single tag
    | string[] // list of tags
    | { tags?: string[]; expectedOutcomes?: string[] };

// Declares the next user message(s) that will be sent along with a set
// of assertions that should be made
export function sayAndAssert(
    messageInput: TestMessageInput,
    expectations: MessageExpectations,
    next: () => void
) {
    const testBuilder = ReplayTestBuilder.get();
    if (testBuilder.isSimulation()) {
        throw new Error("Cannot use sayAndAssert() inside simulate()");
    }
    const messages = parseMessageInput(messageInput);
    testBuilder.addMessages(messages);

    // Handle all variations of MessageExpectations
    if (typeof expectations === "string") {
        // Single tag
        assertTags(expectations);
    } else if (Array.isArray(expectations)) {
        // list of tags
        assertTags(expectations);
    } else if (typeof expectations === "object") {
        // explicit tags and/or expectedOutcomes
        if (expectations.tags) {
            assertTags(expectations.tags);
        }
        if (expectations.expectedOutcomes) {
            addExpectedOutcomes(expectations.expectedOutcomes);
        }
    }

    next();
    testBuilder.popMessages(messages.length);
}

type SimulateMessageInput =
    | TestMessageInput
    | {
          instructions: TestMessageInput;
          options?: ReplaySimulationOptions;
          issueIds?: string[];
      };

export function simulate(messageInput: SimulateMessageInput, next: () => void) {
    const testBuilder = ReplayTestBuilder.get();
    let simulationStartIndex: number | undefined;
    if (testBuilder.getMessageCount() > 0 && !testBuilder.isSimulation()) {
        simulationStartIndex = testBuilder.getMessageCount();
    }
    const oldIsSimulation = testBuilder.isSimulation();
    testBuilder.setSimulation(true);

    let messages: ReplayTestMessage[];
    let options: ReplaySimulationOptions | undefined;
    let issueIds: string[] | undefined;
    if (typeof messageInput === "object" && "instructions" in messageInput) {
        messages = parseMessageInput(messageInput.instructions);
        options = messageInput.options;
        issueIds = messageInput.issueIds;
    } else {
        messages = parseMessageInput(messageInput);
    }
    testBuilder.addMessages(messages);
    if (options) {
        testBuilder.addSimulationOptions(options);
    }
    if (issueIds) {
        testBuilder.addIssueIds(issueIds);
    }
    if (simulationStartIndex) {
        testBuilder.setSimulationStartIndex(simulationStartIndex);
    }

    next();

    if (simulationStartIndex) {
        testBuilder.setSimulationStartIndex(undefined);
    }
    testBuilder.popMessages(messages.length);
    if (options) {
        testBuilder.popSimulationOptions();
    }
    if (issueIds) {
        testBuilder.popIssueIds();
    }
    if (oldIsSimulation !== testBuilder.isSimulation()) {
        testBuilder.setSimulation(oldIsSimulation);
    }
}

// Declares one or more tag assertions that are evaluated at this point in the conversation
// (after the agent response to the preceding user message)
function assertTags(tagOrTags: string | string[]) {
    const testBuilder = ReplayTestBuilder.get();
    if (testBuilder.getMessageCount() === 0) {
        throw new Error("Cannot assertTags() before a say()");
    }

    const assertions = Array.isArray(tagOrTags) ? tagOrTags : [tagOrTags];
    testBuilder.addTagAssertions(assertions);
}

function addExpectedOutcomes(expectedOutcomes: string | string[]) {
    const testBuilder = ReplayTestBuilder.get();
    if (testBuilder.getMessageCount() === 0) {
        throw new Error("Cannot addExpectedOutcomes() before a say()");
    }
    testBuilder.addExpectedOutcomes(ensureList(expectedOutcomes));
}

function addExpectedExtractions(expectedExtractions: string | string[]) {
    const testBuilder = ReplayTestBuilder.get();
    if (testBuilder.getMessageCount() === 0) {
        throw new Error("Cannot addExpectedExtractions() before a say()");
    }
    testBuilder.addExpectedExtractions(ensureList(expectedExtractions));
}

function ensureList<T>(optionalSingleOrList?: T | T[]): T[] {
    return optionalSingleOrList === undefined
        ? []
        : Array.isArray(optionalSingleOrList)
          ? optionalSingleOrList
          : [optionalSingleOrList];
}

const userSimulationOptionKeys = [
    "maxMessages",
    "temperature",
    "skipTersenessFilter",
    "languageCode",
    "writingStyle",
    "runMonitors",
    "simulateSpeech",
] as const;

const systemsSimulationOptionKeys = [
    "simulateTools",
    "simulateIntegrations",
    "accountState",
] as const;

function findMisplacedKeys(
    options: { [key: string]: unknown } | undefined,
    keys: readonly string[]
): string[] {
    if (!options) {
        return [];
    }
    return keys.filter(key => key in options);
}

function validateSimulationOptionBuckets(
    simulationOptions?: ReplaySimulationOptions,
    systemsSimulationOptions?: ReplaySystemsSimulationOptions
) {
    const misplacedSystemsKeys = findMisplacedKeys(
        simulationOptions as { [key: string]: unknown } | undefined,
        systemsSimulationOptionKeys
    );
    if (misplacedSystemsKeys.length > 0) {
        throw new Error(
            `simulationOptions contains systems simulation keys (${misplacedSystemsKeys.join(", ")}); use systemsSimulationOptions instead`
        );
    }

    const misplacedUserKeys = findMisplacedKeys(
        systemsSimulationOptions as { [key: string]: unknown } | undefined,
        userSimulationOptionKeys
    );
    if (misplacedUserKeys.length > 0) {
        throw new Error(
            `systemsSimulationOptions contains user simulation keys (${misplacedUserKeys.join(", ")}); use simulationOptions instead`
        );
    }
}

export type TestOptions = {
    messages?: TestMessageInput;
    // tags based assertions
    assertions?: string | string[];
    // natural language based assertions
    expectedOutcomes?: string | string[];
    // natural language based assertions on the memory extraction output
    expectedExtractions?: string | string[];
    categories?: string | string[];
    name?: string;
    agentId?: string | string[];
    isSimulation?: boolean;
    simulationOptions?: ReplaySimulationOptions;
    systemsSimulationOptions?: ReplaySystemsSimulationOptions;
    issueIds?: string[];
    simulationStartIndex?: number;
    isCritical?: boolean;
};

export type Scenario = {
    // stable identifier for the scenario. changes to other fields show up as
    // edits to the same simulation as long this field remains unchanged.
    //
    // This field is marked as optional for backwards compatibility reasons
    // only. It should always be specified so that simulation version history
    // works correctly.
    testId?: string;

    title: string;
    description?: string;
    fixture: {
        identifiers?: { [key: string]: any };
        variables?: { [key: string]: string | undefined };
        secrets?: { [key: string]: string | undefined };
        agentMemory?: MockMemory;
        userDevice?: Device;
        conversationInfo?: TestConversationInfo;
        instructions: string;
        initialMessages?: (string | TestMessage)[];
        attachmentData?: {
            description: string;
            attachments: TestMessageAttachment[];
            attachmentMessage?: string; // message that gets sent along with these attachments
        }[];
    };
    options?: ReplaySimulationOptions;
    systemsSimulationOptions?: ReplaySystemsSimulationOptions;
    meta?: {
        issueIds?: string[];
    };
    // tags based assertions
    assertions?: string | string[];
    // natural language based assertions
    expectedOutcomes?: string | string[];
    // natural language based assertions on the memory extraction output
    expectedExtractions?: string | string[];
    isCritical?: boolean;
};

type Next = (() => void) | Scenario[];

function handleNext(next: Next) {
    if (typeof next === "function") {
        next();
    } else {
        next.forEach(scenarioToTest);
    }
}

type TestMessageInput = string | TestMessage | (string | TestMessage)[];

function parseMessageInput(messageInput: TestMessageInput): ReplayTestMessage[] {
    let testMessages = [];
    if (typeof messageInput === "string") {
        testMessages = [{ text: messageInput }];
    } else if (Array.isArray(messageInput)) {
        testMessages = messageInput.map(message => {
            if (typeof message === "string") {
                return { text: message };
            } else {
                return message;
            }
        });
    } else {
        testMessages = [messageInput];
    }
    return testMessages.map(m => {
        return {
            content: m.text,
            attachments: m.attachments?.map(attachment => ({
                type: attachment.type,
                data: JSON.stringify(attachment.data),
            })),
            attachmentMessage: m.attachmentMessage,
        };
    });
}

export type TestMessage = {
    text?: string;
    attachments?: TestMessageAttachment[];
    attachmentMessage?: string;
};

export type TestMessageAttachment = {
    type: "file" | "custom";
    data: { [key: string]: any };
};

const FAILING_CATEGORY = "failing";
const SMOKE_CATEGORY = "smoke-test";
export const INTERNAL_CATEGORIES = [FAILING_CATEGORY, SMOKE_CATEGORY];

// Defines a replay test for the preceding user messages with the given id, along with a set of
// assertions, optional set of categories, and optional set of user messages.
// Required at all leaf nodes (final messages).
export function test(id: string, options?: TestOptions) {
    const testBuilder = ReplayTestBuilder.get();
    if (testBuilder.getMessageCount() > 0) {
        if (options?.isSimulation === false && testBuilder.isSimulation() === true) {
            throw new Error("Cannot use say() inside simulate()");
        }
    } else {
        testBuilder.setSimulation(options?.isSimulation ?? false);
    }

    validateSimulationOptionBuckets(options?.simulationOptions, options?.systemsSimulationOptions);

    if (options?.simulationStartIndex) {
        testBuilder.setSimulationStartIndex(options.simulationStartIndex);
    }

    if (options?.simulationOptions) {
        if (!testBuilder.isSimulation()) {
            throw new Error("Cannot use simulationOptions outside of simulate()");
        }
        testBuilder.addSimulationOptions(options.simulationOptions);
    }
    if (options?.systemsSimulationOptions) {
        testBuilder.addSystemsSimulationOptions(options.systemsSimulationOptions);
    }

    let messages = [];
    if (options?.messages) {
        messages = parseMessageInput(options.messages);
        testBuilder.addMessages(messages);
    }
    if (testBuilder.getMessageCount() === 0) {
        throw new Error(`Cannot create test with no messages: id=${id}`);
    }

    let previousAssertions: ReplayTestAssertions | undefined;
    if (options?.assertions) {
        previousAssertions = testBuilder.getLastMessageAssertions();
        assertTags(options.assertions);
    }

    if (options?.expectedOutcomes) {
        addExpectedOutcomes(options.expectedOutcomes);
    }

    if (options?.expectedExtractions) {
        addExpectedExtractions(options.expectedExtractions);
    }

    if (options?.issueIds) {
        testBuilder.addIssueIds(options.issueIds);
    }

    if (options?.isCritical) {
        testBuilder.setCritical(options.isCritical);
    }

    const categories = ensureList(options?.categories);
    const agentIds = ensureList(options?.agentId);

    // Actually create the test
    testBuilder.saveTest(id, categories, agentIds, options?.name);

    // Unwind the test state changes from above
    if (messages.length > 0) {
        testBuilder.popMessages(messages.length);
    } else if (options?.assertions ?? options?.expectedOutcomes ?? options?.expectedExtractions) {
        // If we added assertions in this test, we want to reset back to the original
        // set of assertions on the last message of the test (since these test assertions
        // could be based on a post-conversation hook running, etc). However, if we
        // also appended messages in this test (the above case), then we should not
        // reset assertions, since the message with the modified assertions has been
        // popped off
        testBuilder.resetLastMessageAssertions(previousAssertions);
    }

    if (options?.isCritical) {
        testBuilder.setCritical(false);
    }
    if (options?.issueIds) {
        testBuilder.popIssueIds();
    }
    if (options?.simulationOptions) {
        testBuilder.popSimulationOptions();
    }
    if (options?.systemsSimulationOptions) {
        testBuilder.popSystemsSimulationOptions();
    }
    if (options?.simulationStartIndex) {
        testBuilder.setSimulationStartIndex(undefined);
    }
    if (testBuilder.getMessageCount() === 0) {
        testBuilder.setSimulation(false);
    }
}

test.failing = function (id: string, options?: TestOptions) {
    const testBuilder = ReplayTestBuilder.get();
    testBuilder.addCategories([FAILING_CATEGORY]);
    test(id, options);
    testBuilder.popCategories();
};

test.smoke = function (id: string, options?: TestOptions) {
    const testBuilder = ReplayTestBuilder.get();
    testBuilder.addCategories([SMOKE_CATEGORY]);
    test(id, options);
    testBuilder.popCategories();
};

test.critical = function (id: string, options?: TestOptions) {
    const testBuilder = ReplayTestBuilder.get();
    testBuilder.setCritical(true);
    test(id, options);
    testBuilder.setCritical(false);
};

export function describe(description: string, categoryOrCategories: string | string[], next: Next) {
    if (!description) {
        throw new Error("describe() must have non-empty description");
    }
    const testBuilder = ReplayTestBuilder.get();
    if (categoryOrCategories) {
        const categories = ensureList(categoryOrCategories);
        testBuilder.addCategories(categories);
    }
    testBuilder.addDescription(description);
    handleNext(next);
    testBuilder.popDescription();
    if (categoryOrCategories) {
        testBuilder.popCategories();
    }
}

function scenarioToTest(scenario: Scenario, index: number) {
    const testBuilder = ReplayTestBuilder.get();
    const categories = testBuilder.getCategories().join("-");
    // derive testId if the user has not specified one
    // TODO: emit a warning that will show up in `pnpm sierra watch` output when testId is missing
    const testId =
        scenario.testId ??
        `${scenario.title
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, "-")
            .replace(/(^-|-$)/g, "")}-${categories}-${index.toString().padStart(3, "0")}`;

    const {
        identifiers,
        instructions,
        variables,
        secrets,
        agentMemory,
        userDevice,
        conversationInfo,
        initialMessages,
        attachmentData,
    } = scenario.fixture;

    const messages: TestMessageInput = [...(initialMessages ?? [])];
    if (identifiers) {
        let accountInfo = "## Account information";
        Object.keys(identifiers)
            .filter(key => identifiers[key] !== undefined)
            .forEach(key => {
                accountInfo += `\n- ${key}: ${identifiers[key]}`;
            });
        messages.push(accountInfo);
    }
    messages.push(`## Reason for contacting support\n${instructions}`);

    if (attachmentData) {
        messages.push(
            ...attachmentData.map(a => {
                return {
                    text: a.description,
                    attachments: a.attachments,
                    attachmentMessage: a.attachmentMessage,
                };
            })
        );
    }

    let oldDevice;
    if (userDevice) {
        oldDevice = testBuilder.getDevice();
        testBuilder.setDevice(userDevice);
    }

    let oldConversationInfo;
    if (conversationInfo) {
        oldConversationInfo = testBuilder.getConversationInfo();
        testBuilder.setConversationInfo({ ...oldConversationInfo, ...conversationInfo });
    }

    const memory: Memory = {};
    if (variables) {
        memory.variables = Object.keys(variables)
            .filter(key => variables[key] !== undefined)
            .map(key => ({ name: key, value: variables[key] ?? "" }));
    }
    if (secrets) {
        memory.secrets = Object.keys(secrets)
            .filter(key => secrets[key] !== undefined)
            .map(key => ({ name: key, value: secrets[key] ?? "" }));
    }
    if (memory.variables ?? memory.secrets) {
        testBuilder.addMemory(memory);
    }

    if (agentMemory) {
        testBuilder.addMockMemory(agentMemory);
    }

    test(testId, {
        name: scenario.title,
        messages,
        assertions: scenario.assertions,
        expectedOutcomes: scenario.expectedOutcomes,
        expectedExtractions: scenario.expectedExtractions,
        isSimulation: true,
        simulationOptions: scenario.options,
        systemsSimulationOptions: scenario.systemsSimulationOptions,
        categories: ["scenario"],
        issueIds: scenario.meta?.issueIds,
        simulationStartIndex: initialMessages?.length ?? 0,
        isCritical: scenario.isCritical,
    });

    if (agentMemory) {
        testBuilder.popMockMemory();
    }
    if (memory.variables ?? memory.secrets) {
        testBuilder.popMemory();
    }
    if (conversationInfo) {
        testBuilder.setConversationInfo(oldConversationInfo);
    }
    if (userDevice) {
        testBuilder.setDevice(oldDevice);
    }
}
